class _Literal:
    __slots__ = ('ch',)

    def __init__(self, ch):
        self.ch = ch


class _AnyChar:
    pass


class _CharClass:
    __slots__ = ('chars', 'ranges', 'negate')

    def __init__(self, chars, ranges, negate):
        self.chars = chars
        self.ranges = ranges
        self.negate = negate

    def contains(self, ch):
        in_class = ch in self.chars
        if not in_class:
            for lo, hi in self.ranges:
                if lo <= ch <= hi:
                    in_class = True
                    break
        return in_class != self.negate


class _Concat:
    __slots__ = ('items',)

    def __init__(self, items):
        self.items = items


class _Alt:
    __slots__ = ('items',)

    def __init__(self, items):
        self.items = items


class _Star:
    __slots__ = ('child',)

    def __init__(self, child):
        self.child = child


class _Plus:
    __slots__ = ('child',)

    def __init__(self, child):
        self.child = child


class _Opt:
    __slots__ = ('child',)

    def __init__(self, child):
        self.child = child


def _parse(pattern):
    n = len(pattern)
    pos = 0

    def parse_alt():
        nonlocal pos
        branches = [parse_concat()]
        while pos < n and pattern[pos] == '|':
            pos += 1
            branches.append(parse_concat())
        if len(branches) == 1:
            return branches[0]
        return _Alt(branches)

    def parse_concat():
        nonlocal pos
        items = []
        while pos < n and pattern[pos] not in '|)':
            items.append(parse_factor())
        if len(items) == 1:
            return items[0]
        return _Concat(items)

    def parse_factor():
        nonlocal pos
        atom = parse_atom()
        if pos < n and pattern[pos] in '*+?':
            q = pattern[pos]
            pos += 1
            if q == '*':
                return _Star(atom)
            if q == '+':
                return _Plus(atom)
            return _Opt(atom)
        return atom

    def parse_atom():
        nonlocal pos
        c = pattern[pos]
        if c == '(':
            pos += 1
            node = parse_alt()
            pos += 1
            return node
        if c == '[':
            pos += 1
            negate = False
            if pos < n and pattern[pos] == '^':
                negate = True
                pos += 1
            chars = set()
            ranges = []
            while pattern[pos] != ']':
                if pos + 2 < n and pattern[pos + 1] == '-' and pattern[pos + 2] != ']':
                    ranges.append((pattern[pos], pattern[pos + 2]))
                    pos += 3
                else:
                    chars.add(pattern[pos])
                    pos += 1
            pos += 1
            return _CharClass(chars, ranges, negate)
        if c == '.':
            pos += 1
            return _AnyChar()
        pos += 1
        return _Literal(c)

    return parse_alt()


def _match_node(node, text, pos, cont):
    if isinstance(node, _Literal):
        if pos < len(text) and text[pos] == node.ch:
            return cont(pos + 1)
        return False

    if isinstance(node, _AnyChar):
        if pos < len(text):
            return cont(pos + 1)
        return False

    if isinstance(node, _CharClass):
        if pos < len(text) and node.contains(text[pos]):
            return cont(pos + 1)
        return False

    if isinstance(node, _Concat):
        items = node.items

        def step(i, p):
            if i == len(items):
                return cont(p)
            return _match_node(items[i], text, p, lambda p2: step(i + 1, p2))

        return step(0, pos)

    if isinstance(node, _Alt):
        for branch in node.items:
            if _match_node(branch, text, pos, cont):
                return True
        return False

    if isinstance(node, _Star):
        def try_more(p):
            if p == pos:
                return cont(p)
            return _match_node(node, text, p, cont)

        if _match_node(node.child, text, pos, try_more):
            return True
        return cont(pos)

    if isinstance(node, _Plus):
        return _match_node(
            node.child, text, pos,
            lambda p: _match_node(_Star(node.child), text, p, cont)
        )

    if isinstance(node, _Opt):
        if _match_node(node.child, text, pos, cont):
            return True
        return cont(pos)

    return False


def match(pattern: str, text: str) -> bool:
    ast = _parse(pattern)
    return _match_node(ast, text, 0, lambda p: p == len(text))
